import * as React from "react";
import { tokens } from "../theme/tokens";

interface SuggestionCardProps {
  icon: string;
  title: string;
  subtitle: string;
  onClick: () => void;
}

const SuggestionCard: React.FC<SuggestionCardProps> = ({ icon, title, subtitle, onClick }) => {
  const [hovered, setHovered] = React.useState(false);

  return (
    <button
      onClick={onClick}
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
      style={{
        backgroundColor: tokens.colors.surface,
        border: `1px solid ${tokens.colors.border}`,
        borderRadius: tokens.radius.md,
        padding: `${tokens.spacing.md}px`,
        textAlign: "left",
        cursor: "pointer",
        boxShadow: hovered ? tokens.shadow.cardHover : tokens.shadow.card,
        transform: hovered ? "translateY(-2px)" : "translateY(0)",
        transition: "box-shadow 0.2s ease, transform 0.2s ease",
        display: "flex",
        flexDirection: "column",
        gap: tokens.spacing.xs,
        width: "100%",
        boxSizing: "border-box",
      }}
    >
      <span style={{ fontSize: "20px", lineHeight: 1 }}>{icon}</span>
      <span
        style={{
          fontSize: tokens.font.body.size,
          fontWeight: 600,
          color: tokens.colors.text,
          lineHeight: 1.3,
        }}
      >
        {title}
      </span>
      <span
        style={{
          fontSize: tokens.font.caption.size,
          fontWeight: tokens.font.caption.weight,
          color: tokens.colors.textSecondary,
          lineHeight: 1.4,
        }}
      >
        {subtitle}
      </span>
    </button>
  );
};

export default SuggestionCard;
