import * as React from "react";
import { tokens } from "../theme/tokens";
import SuggestionCard from "./SuggestionCard";

const SUGGESTIONS = [
  {
    icon: "💬",
    title: "Summarise this email",
    subtitle: "Summarise Email",
    prompt: "Summarise this email.",
  },
  {
    icon: "💬",
    title: "Summarise and reply to this email",
    subtitle: "Summarise and Reply",
    prompt: "Summarise this email and draft a reply.",
  },
  {
    icon: "📋",
    title: "What are the main takeaways?",
    subtitle: "List the main takeaways from this email in a bulleted list.",
    prompt: "List the main takeaways from this email in a bulleted list.",
  },
];

interface SuggestionCardsProps {
  onSend: (prompt: string) => void;
}

const SuggestionCards: React.FC<SuggestionCardsProps> = ({ onSend }) => {
  const [expanded, setExpanded] = React.useState(false);
  const visible = expanded ? SUGGESTIONS : SUGGESTIONS.slice(0, 2);

  return (
    <div
      style={{
        padding: `0 ${tokens.spacing.lg}px ${tokens.spacing.md}px`,
        display: "flex",
        flexDirection: "column",
        gap: tokens.spacing.sm,
      }}
    >
      <div
        style={{
          display: "grid",
          gridTemplateColumns: "1fr 1fr",
          gap: tokens.spacing.sm,
        }}
      >
        {visible.map((s) => (
          <SuggestionCard
            key={s.prompt}
            icon={s.icon}
            title={s.title}
            subtitle={s.subtitle}
            onClick={() => onSend(s.prompt)}
          />
        ))}
      </div>

      <div style={{ display: "flex", justifyContent: "flex-end" }}>
        <button
          onClick={() => setExpanded((v) => !v)}
          style={{
            background: "transparent",
            border: `1px solid ${tokens.colors.border}`,
            borderRadius: tokens.radius.pill,
            padding: `${tokens.spacing.xs}px ${tokens.spacing.md}px`,
            fontSize: tokens.font.label.size,
            fontWeight: tokens.font.label.weight,
            color: tokens.colors.textSecondary,
            cursor: "pointer",
            display: "flex",
            alignItems: "center",
            gap: 4,
          }}
        >
          {expanded ? "See less ∧" : "See more ∨"}
        </button>
      </div>
    </div>
  );
};

export default SuggestionCards;
