import * as React from "react";
import { tokens } from "../theme/tokens";
import Header from "./Header";
import ConversationView from "./ConversationView";
import SuggestionCards from "./SuggestionCards";
import ChatInput from "./ChatInput";
import { Message } from "./MessageBubble";
import { useGenerateReply } from "../hooks/useBasicService";
import { getEmailContext, insertText } from "../taskpane";

const LOADING_PHRASES = [
  "Herding the cats...",
  "Boiling the ocean...",
  "Circling back with the AI...",
  "Leveraging synergies...",
  "Touching base with GPT...",
  "Thinking outside the inbox...",
  "Picking the low-hanging fruit...",
  "Moving the needle...",
  "Generating enterprise value...",
  "Consulting the reply oracle...",
  "Summoning professional prose...",
  "Banishing filler words...",
  "Running it up the flagpole...",
  "Eating the frog...",
  "Teaching AI to write emails...",
  "Counting tokens...",
  "Spell-checking... twice...",
  "Adding buzzwords... removing buzzwords...",
  "Asking the AI nicely...",
  "Making it sound smart...",
];

interface AppProps {
  title: string;
}

const App: React.FC<AppProps> = ({ title }) => {
  const { mutate, isPending } = useGenerateReply();
  const [messages, setMessages] = React.useState<Message[]>([]);
  const [instruction, setInstruction] = React.useState("");
  const [headerTitle, setHeaderTitle] = React.useState(title);

  /* Cycle loading phrases in the header while pending */
  React.useEffect(() => {
    let interval: ReturnType<typeof setInterval> | null = null;
    if (isPending) {
      const shuffled = [...LOADING_PHRASES].sort(() => Math.random() - 0.5);
      let idx = 0;
      setHeaderTitle(shuffled[idx]);
      interval = setInterval(() => {
        idx = (idx + 1) % shuffled.length;
        setHeaderTitle(shuffled[idx]);
      }, 1800);
    } else {
      setHeaderTitle(title);
    }
    return () => { if (interval !== null) clearInterval(interval); };
  }, [isPending, title]);

  const handleSend = async (prompt?: string) => {
    const text = (prompt ?? instruction).trim();
    if (!text) return;

    /* Find last AI draft to use as context */
    const lastDraft = [...messages].reverse().find((m) => m.role === "ai" && m.isDraft);

    /* Add user message to conversation */
    setMessages((prev) => [...prev, { role: "user", content: text }]);
    setInstruction("");

    try {
      const context = await getEmailContext();
      mutate(
        {
          ...context,
          draft: lastDraft?.content ?? undefined,
          instruction: text,
        },
        {
          onSuccess: ({ reply, intent }) => {
            setMessages((prev) => [
              ...prev,
              {
                role: "ai",
                content: reply,
                isDraft: intent !== "qa",
              },
            ]);
          },
          onError: (error) => {
            console.error("Failed to generate reply:", error);
            setMessages((prev) => [
              ...prev,
              {
                role: "ai",
                content: `Something went wrong: ${error instanceof Error ? error.message : "Unknown error"}`,
                isDraft: false,
              },
            ]);
          },
        }
      );
    } catch (error) {
      console.error("Failed to read email context:", error);
      setMessages((prev) => [
        ...prev,
        {
          role: "ai",
          content: `Could not read email: ${error instanceof Error ? error.message : "Unknown error"}`,
          isDraft: false,
        },
      ]);
    }
  };

  const handleInsert = (text: string) => {
    insertText(text);
    /* Mark the draft as no longer insertable */
    setMessages((prev) =>
      prev.map((m) => (m.content === text && m.isDraft ? { ...m, isDraft: false } : m))
    );
  };

  const handleDiscard = (index: number) => {
    setMessages((prev) => prev.map((m, i) => (i === index ? { ...m, isDraft: false } : m)));
  };

  const hasMessages = messages.length > 0;

  return (
    <div
      style={{
        height: "100vh",
        display: "flex",
        flexDirection: "column",
        backgroundColor: tokens.colors.background,
        boxSizing: "border-box",
        overflow: "hidden",
      }}
    >
      <Header title={headerTitle} />

      {hasMessages ? (
        <ConversationView
          messages={messages}
          onInsert={handleInsert}
          onDiscard={handleDiscard}
        />
      ) : (
        <div style={{ flex: 1 }} />
      )}

      <SuggestionCards onSend={handleSend} />

      <ChatInput
        value={instruction}
        onChange={setInstruction}
        onSend={() => handleSend()}
        disabled={isPending}
        placeholder={hasMessages ? "Refine or ask a follow-up... (Enter to send)" : "How can I help? (Enter to send)"}
      />
    </div>
  );
};

export default App;
