import * as React from "react";
import { tokens } from "../theme/tokens";

export interface Message {
  role: "user" | "ai";
  content: string;
  /** Optional: shows insert button for AI reply drafts */
  isDraft?: boolean;
}

interface MessageBubbleProps {
  message: Message;
  onInsert?: (text: string) => void;
  onDiscard?: () => void;
}

const MessageBubble: React.FC<MessageBubbleProps> = ({ message, onInsert, onDiscard }) => {
  const isUser = message.role === "user";

  if (isUser) {
    return (
      <div style={{ display: "flex", justifyContent: "flex-end", marginBottom: tokens.spacing.sm }}>
        <div
          style={{
            backgroundColor: tokens.colors.userBubble,
            color: "#fff",
            borderRadius: `${tokens.radius.md} ${tokens.radius.md} 4px ${tokens.radius.md}`,
            padding: `${tokens.spacing.sm}px ${tokens.spacing.md}px`,
            maxWidth: "80%",
            fontSize: tokens.font.body.size,
            lineHeight: 1.5,
            wordBreak: "break-word",
          }}
        >
          {message.content}
        </div>
      </div>
    );
  }

  /* AI bubble */
  return (
    <div style={{ display: "flex", flexDirection: "column", gap: tokens.spacing.xs, marginBottom: tokens.spacing.sm }}>
      {/* Copilot-style header */}
      <div style={{ display: "flex", alignItems: "center", gap: tokens.spacing.xs }}>
        <div
          style={{
            width: 24,
            height: 24,
            borderRadius: "50%",
            backgroundColor: tokens.colors.primary,
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
          }}
        >
          <span style={{ color: "#fff", fontSize: "11px", fontWeight: 700 }}>AI</span>
        </div>
        <span
          style={{
            fontSize: tokens.font.caption.size,
            fontWeight: tokens.font.label.weight,
            color: tokens.colors.textSecondary,
          }}
        >
          Assistant
        </span>
      </div>

      <div
        style={{
          backgroundColor: tokens.colors.aiBubble,
          color: tokens.colors.text,
          borderRadius: `4px ${tokens.radius.md} ${tokens.radius.md} ${tokens.radius.md}`,
          padding: `${tokens.spacing.sm}px ${tokens.spacing.md}px`,
          boxShadow: tokens.shadow.card,
          border: `1px solid ${tokens.colors.border}`,
          fontSize: tokens.font.body.size,
          lineHeight: 1.6,
          whiteSpace: "pre-wrap",
          wordBreak: "break-word",
        }}
      >
        {message.content}
      </div>

      {message.isDraft && (
        <div style={{ display: "flex", gap: tokens.spacing.sm, paddingLeft: 32 }}>
          <button
            onClick={() => onInsert?.(message.content)}
            style={{
              backgroundColor: tokens.colors.primary,
              color: "#fff",
              border: "none",
              borderRadius: tokens.radius.sm,
              padding: `${tokens.spacing.xs}px ${tokens.spacing.md}px`,
              fontSize: tokens.font.label.size,
              fontWeight: tokens.font.label.weight,
              cursor: "pointer",
            }}
          >
            Insert reply
          </button>
          <button
            onClick={onDiscard}
            style={{
              backgroundColor: "transparent",
              color: tokens.colors.textSecondary,
              border: `1px solid ${tokens.colors.border}`,
              borderRadius: tokens.radius.sm,
              padding: `${tokens.spacing.xs}px ${tokens.spacing.md}px`,
              fontSize: tokens.font.label.size,
              fontWeight: tokens.font.label.weight,
              cursor: "pointer",
            }}
          >
            Discard
          </button>
        </div>
      )}
    </div>
  );
};

export default MessageBubble;
