import * as React from "react";
import { tokens } from "../theme/tokens";
import { ShimmerButton } from "./ShimmerButton";

/* global HTMLTextAreaElement */

interface ChatInputProps {
  value: string;
  onChange: (value: string) => void;
  onSend: () => void;
  disabled?: boolean;
  placeholder?: string;
}

const ChatInput: React.FC<ChatInputProps> = ({
  value,
  onChange,
  onSend,
  disabled = false,
  placeholder = "How can I help? (Enter to send)",
}) => {
  const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault();
      if (!disabled && value.trim()) onSend();
    }
  };

  return (
    <div
      style={{
        backgroundColor: tokens.colors.surface,
        borderTop: `1px solid ${tokens.colors.border}`,
        padding: `${tokens.spacing.sm}px ${tokens.spacing.lg}px ${tokens.spacing.md}px`,
        boxSizing: "border-box",
      }}
    >
      <div
        style={{
          display: "flex",
          flexDirection: "column",
          gap: tokens.spacing.sm,
          backgroundColor: tokens.colors.background,
          borderRadius: tokens.radius.lg,
          padding: `${tokens.spacing.md}px ${tokens.spacing.lg}px ${tokens.spacing.sm}px`,
          boxShadow: tokens.shadow.input,
          border: `1px solid ${tokens.colors.border}`,
        }}
      >
        <textarea
          value={value}
          onChange={(e) => onChange(e.target.value)}
          onKeyDown={handleKeyDown}
          placeholder={placeholder}
          disabled={disabled}
          rows={2}
          style={{
            background: "transparent",
            border: "none",
            outline: "none",
            resize: "none",
            fontSize: tokens.font.body.size,
            fontWeight: tokens.font.body.weight,
            lineHeight: 1.5,
            width: "100%",
            padding: 0,
            fontFamily: "inherit",
            color: disabled ? tokens.colors.textSecondary : tokens.colors.text,
            cursor: disabled ? "not-allowed" : "text",
          }}
        />
        <div style={{ display: "flex", justifyContent: "flex-end", alignItems: "center" }}>
          <ShimmerButton
            background={tokens.colors.accent}
            shimmerColor="#fff"
            shimmerDuration="2.5s"
            borderRadius={tokens.radius.pill}
            disabled={disabled || !value.trim()}
            onClick={onSend}
            style={{
              padding: "6px 16px",
              fontSize: tokens.font.label.size,
              fontWeight: tokens.font.label.weight,
              opacity: disabled || !value.trim() ? 0.55 : 1,
              cursor: disabled || !value.trim() ? "not-allowed" : "pointer",
            }}
          >
            {disabled ? "•••" : "Send ↑"}
          </ShimmerButton>
        </div>
      </div>
    </div>
  );
};

export default ChatInput;
